def describe_image(image_path: str) -> str:
    with open(image_path, "rb") as f:
        image_data = base64.standard_b64encode(f.read()).decode()
    response = client.chat.completions.create(
        model="gpt-4o",
        messages=[{"role": "user", "content": [
            {"type": "text", "text": "Describe this image in detail for image generation."},
            {"type": "image_url",
             "image_url": {"url": f"data:image/jpeg;base64,{image_data}"}}
        ]}])
    return response.choices[0].message.content

def reimagine_image(image_path: str, style_modifier: str = "") -> dict:
    description = describe_image(image_path)
    prompt = f"{description}. {style_modifier}" if style_modifier else description
    return generate_image(prompt)

def safe_batch_generate(prompts: list[str], size="1024x1024", delay=12.0) -> list[dict]:
    """Generate with rate-limit backoff. 5 img/min tier-1 = 12s/img."""
    client = OpenAI()
    results = []
    for i, prompt in enumerate(prompts):
        for attempt in range(3):
            try:
                resp = client.images.generate(
                    model="dall-e-3", prompt=prompt, size=size, n=1)
                results.append({"prompt": prompt, "url": resp.data[0].url,
                                 "revised": resp.data[0].revised_prompt})
                break
            except RateLimitError:
                time.sleep(delay * (2 ** attempt))
        else:
            results.append({"prompt": prompt, "error": "rate_limit"})
        if i < len(prompts) - 1:
            time.sleep(delay)
    return results
